create table revenues (
    revenue_id   number generated by default as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 cache 20 noorder
    nocycle nokeep noscale not null enable,
    team_id      number not null enable,
    revenue_date date not null enable,
    category     varchar2(40 byte) not null enable,
    description  varchar2(240 byte),
    amount       number(12, 2) not null enable,
    source_name  varchar2(120 byte)
);

alter table revenues
    add constraint revenues_amount_ck check ( amount >= 0 ) enable;

alter table revenues
    add constraint revenues_category_ck
        check ( category in ( 'TICKET_SALES', 'SPONSORSHIP', 'MERCHANDISE', 'BROADCAST', 'CONCESSIONS',
                              'OTHER' ) ) enable;

alter table revenues
    add constraint revenues_pk primary key ( revenue_id )
        using index enable;


